package org.apache.commons.math3.linear;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.apache.commons.math3.linear.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.apache.commons.math3.linear.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.math3.linear.ArrayRealVector;
import org.apache.commons.math3.linear.SparseRealVector;
import org.apache.commons.math3.linear.RealVector;

import java.util.List;
import java.util.Map;

import static org.junit.Assert.*;

public class StepDefs {
    private RealVector v1;
    private RealVector v2;
    private RealVector result;

    @Given("a sparse vector v1 with values:")
    public void a_sparse_vector_v1_with_values(List<Map<String, String>> values) {
        double[] array = new double[3];
        for (Map<String, String> row : values) {
            int index = Integer.parseInt(row.get("index"));
            double value = Double.parseDouble(row.get("value"));
            array[index] = value;
        }
        this.v1 = new SparseRealVector(array);
    }

    @Given("a dense vector v2 with values:")
    public void a_dense_vector_v2_with_values(List<Map<String, String>> values) {
        double[] array = new double[3];
        for (Map<String, String> row : values) {
            int index = Integer.parseInt(row.get("index"));
            double value = Double.parseDouble(row.get("value"));
            array[index] = value;
        }
        this.v2 = new ArrayRealVector(array);
    }

    @When("I compute the element-by-element division of v1 by v2")
    public void i_compute_the_element_by_element_division_of_v1_by_v2() {
        try {
            this.result = v1.ebeDivide(v2);
        } catch (Exception e) {
            // Catch any exceptions during division
            fail("Exception during element-by-element division: " + e.getMessage());
        }
    }

    @Then("the result at index {int} should be NaN")
    public void the_result_at_index_should_be_NaN(Integer index) {
        assertTrue("Expected NaN at index " + index + " but got " + result.getEntry(index),
                   Double.isNaN(result.getEntry(index)));
    }

    @Then("the result at index {int} should be {double}")
    public void the_result_at_index_should_be(Integer index, Double expected) {
        assertEquals("Value at index " + index + " should be " + expected,
                     expected, result.getEntry(index), 0.0001);
    }
}

